  SIGNUP = 'SIGNUP',
  PATH_SELECTION = 'PATH_SELECTION',
  ACTION_SELECTION = 'ACTION_SELECTION',
  CHATBOT = 'CHATBOT',
  BOOK_DOCTOR = 'BOOK_DOCTOR',
  LIVE_QUEUE = 'LIVE_QUEUE',
  NEARBY_QUEUES = 'NEARBY_QUEUES',
